UPDATE user_stats


        SET str_exp       = #{newExp},
            str_level     = #{newLevel},
            str_daily_exp = #{newDailyExp}


        SET int_exp       = #{newExp},
            int_level     = #{newLevel},
            int_daily_exp = #{newDailyExp}


        SET wil_exp       = #{newExp},
            wil_level     = #{newLevel},
            wil_daily_exp = #{newDailyExp}


        SET vit_exp       = #{newExp},
            vit_level     = #{newLevel},
            vit_daily_exp = #{newDailyExp}


WHERE user_id = #{userId}
